SELECT participant_id, test_score
FROM test_scores
WHERE test_score > 1.95 AND test_type = 'psychological';

SELECT participant_id, age 
FROM participants 
WHERE socioeconomic_status > (SELECT AVG(socioeconomic_status) FROM participants);

SELECT test_type, COUNT(*) AS count
FROM test_scores
GROUP BY test_type;

SELECT COUNT(DISTINCT participant_id) 
FROM test_scores
WHERE test_type = 'psychological' AND test_score > 2.0 AND test_score <= 3.0;

SELECT socioeconomic_status 
FROM participants 
WHERE participant_id = (
    SELECT participant_id 
    FROM education_levels 
    WHERE gpa = (
        SELECT MAX(gpa) 
        FROM education_levels
    )
);

SELECT AVG(test_score) AS average_test_score
FROM test_scores
WHERE test_type = 'Psychological' AND test_date < date('now', '-2 years');
